class Solution:
    def canBeEqual(self, s1: str, s2: str) -> bool:
        # Check if the characters at even indices and odd indices match
        # because allowed swaps only affect characters at positions with difference 2
        # which preserves the parity of indices
        return sorted(s1[::2]) == sorted(s2[::2]) and sorted(s1[1::2]) == sorted(s2[1::2])
